376→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
377→        ObjectMapper mapper = objectMapper.copy();
378→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
379→        SimpleModule module = new SimpleModule();
380→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
381→        mapper.registerModule(module);
382→        JavaType treeNodeType =
383→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
384→        JavaType listType =
385→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
386→        return mapper.readValue(json, listType);
387→    }
