    private String resolveUniqueName(String spaceId, String name, Long parentId) {
        if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, name, parentId)) {
            return name;
        }
        int count = 1;
        while (true) {
            String candidate = name + "(" + count + ")";
            if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, candidate, parentId)) {
                return candidate;
            }
            count++;
        }
    }

    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
                                      Long parentId, Long userId, String sourceSpaceId,
                                      MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
        SpaceNodeVo spaceNodeVo = node.getData();
        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
        String newNodeId = nodeIdMapping.get(oldNodeId);

        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
            newNodeId = "";
        }

        if (newNodeId == null) {
            log.error("No mapping found for node: {}", oldNodeId);
            return;
        }

        String originalName = spaceNodeVo.getName();
        String name = MigrationTypeEnum.CROSS_SERVER.equals(migrationType)
                ? resolveUniqueName(spaceId, originalName, parentId)
                : originalName;
        if (!name.equals(originalName)) {
            log.info("[2010-change-filename] migrate node name conflict, renamed: [{}] -> [{}], spaceId: {}, " +
                            "parentId: {}",
                    originalName,
                    name, spaceId, parentId);
        }

        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
                .appSpaceNodeId(newNodeId)
                .name(name)
                .type(spaceNodeVo.getType())
                .description(spaceNodeVo.getDescription())
                .spaceId(spaceId)
                .createdBy(userId)
                .updatedBy(userId)
                .build();

        spaceNodeService.save(spaceNodeEntity);
        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());

        // 复制文件关联的版本快照
        copyVersionSnapshots(node.getRelId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig, userId);

        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
                        sourceSpaceId, migrationType, migrationConfig);
            }
        }
    }

    /**
     * 迁移文件时，复制其关联的历史版本快照
     */
    private void copyVersionSnapshots(Long originalNodeId, SpaceNodeEntity newSpaceNodeEntity,
                                       String targetSpaceId, String sourceSpaceId,
                                       MigrationTypeEnum migrationType, MigrationConfig migrationConfig,
                                       Long userId) {
        // 文件夹没有版本快照
        if (Objects.equals(newSpaceNodeEntity.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
            return;
        }

        List<CollabspaceVersionSnapshotEntity> snapshots = versionSnapshotService.getByNodeId(
                originalNodeId, VersionSnapshotStatusEnum.ENABLED.getValue());
        if (snapshots.isEmpty()) {
            return;
        }

        log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: originalNodeId={}, newNodeId={}, snapshotCount={}",
                originalNodeId, newSpaceNodeEntity.getId(), snapshots.size());

        for (CollabspaceVersionSnapshotEntity snapshot : snapshots) {
            try {
                SpaceNodeVo snapshotNodeVo = new SpaceNodeVo();
                snapshotNodeVo.setAppSpaceNodeId(snapshot.getSnapshotId());
                snapshotNodeVo.setType(newSpaceNodeEntity.getType());
                snapshotNodeVo.setName(snapshot.getSnapshotName());

                TreeNode<SpaceNodeVo> snapshotTreeNode = new TreeNode<>();
                snapshotTreeNode.setData(snapshotNodeVo);

                List<TreeNode<SpaceNodeVo>> snapshotTree = new ArrayList<>();
                snapshotTree.add(snapshotTreeNode);

                SpaceNodeMigrationResult result = appMigrationChain.executeMigration(
                        snapshotTree, targetSpaceId, sourceSpaceId, migrationType, migrationConfig);

                if (result.getErrorMessage() != null) {
                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed to copy snapshot file, originalNodeId={}, snapshotId={}, error={}",
                            originalNodeId, snapshot.getSnapshotId(), result.getErrorMessage());
                    continue;
                }

                String newSnapshotFileId = result.getNodeIdMapping().get(snapshot.getSnapshotId());
                if (newSnapshotFileId == null) {
                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: no mapping for snapshotId={}", snapshot.getSnapshotId());
                    continue;
                }

                CollabspaceVersionSnapshotEntity newSnapshot = CollabspaceVersionSnapshotEntity.builder()
                        .nodeId(newSpaceNodeEntity.getId())
                        .snapshotId(newSnapshotFileId)
                        .snapshotName(snapshot.getSnapshotName())
                        .snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue())
                        .operatorId(userId)
                        .build();
                versionSnapshotService.save(newSnapshot);

                SpaceNodeEntity snapshotSpaceNode = SpaceNodeEntity.builder()
                        .appSpaceNodeId(newSnapshotFileId)
                        .name(snapshot.getSnapshotName())
                        .type(newSpaceNodeEntity.getType())
                        .description("")
                        .spaceId(targetSpaceId)
                        .createdBy(userId)
                        .updatedBy(userId)
                        .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
                        .build();
                spaceNodeService.save(snapshotSpaceNode);

                log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: copied snapshot, originalSnapshotId={}, newSnapshotId={}, newNodeId={}",
                        snapshot.getSnapshotId(), newSnapshotFileId, newSpaceNodeEntity.getId());

            } catch (Exception e) {
                log.error("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed to copy snapshot, originalNodeId={}, snapshotId={}, error={}",
                        originalNodeId, snapshot.getSnapshotId(), e.getMessage(), e);
            }
        }
    }

    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
        ObjectMapper mapper = objectMapper.copy();
        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
        SimpleModule module = new SimpleModule();
        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
        mapper.registerModule(module);
        JavaType treeNodeType =
                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
        JavaType listType =
                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
        return mapper.readValue(json, listType);
    }

