320→    private void copyVersionSnapshots(Long originalNodeId, SpaceNodeEntity newSpaceNodeEntity,
321→                                       String targetSpaceId, String sourceSpaceId,
322→                                       MigrationTypeEnum migrationType, MigrationConfig migrationConfig,
323→                                       Long userId) {
324→        // 文件夹没有版本快照
325→        if (Objects.equals(newSpaceNodeEntity.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
326→            return;
327→        }
328→
329→        List<CollabspaceVersionSnapshotEntity> snapshots = versionSnapshotService.getByNodeId(
330→                originalNodeId, VersionSnapshotStatusEnum.ENABLED.getValue());
331→        if (snapshots.isEmpty()) {
332→            return;
333→        }
334→
335→        log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: originalNodeId={}, newNodeId={}, snapshotCount={}",
336→                originalNodeId, newSpaceNodeEntity.getId(), snapshots.size());
337→
338→        for (CollabspaceVersionSnapshotEntity snapshot : snapshots) {
339→            try {
340→                SpaceNodeVo snapshotNodeVo = new SpaceNodeVo();
341→                snapshotNodeVo.setAppSpaceNodeId(snapshot.getSnapshotId());
342→                snapshotNodeVo.setType(newSpaceNodeEntity.getType());
343→                snapshotNodeVo.setName(snapshot.getSnapshotName());
344→
345→                TreeNode<SpaceNodeVo> snapshotTreeNode = new TreeNode<>();
346→                snapshotTreeNode.setData(snapshotNodeVo);
347→
348→                List<TreeNode<SpaceNodeVo>> snapshotTree = new ArrayList<>();
349→                snapshotTree.add(snapshotTreeNode);
350→
351→                SpaceNodeMigrationResult result = appMigrationChain.executeMigration(
352→                        snapshotTree, targetSpaceId, sourceSpaceId, migrationType, migrationConfig);
353→
354→                if (result.getErrorMessage() != null) {
355→                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed to copy snapshot file, originalNodeId={}, snapshotId={}, error={}",
356→                            originalNodeId, snapshot.getSnapshotId(), result.getErrorMessage());
357→                    continue;
358→                }
359→
360→                String newSnapshotFileId = result.getNodeIdMapping().get(snapshot.getSnapshotId());
361→                if (newSnapshotFileId == null) {
362→                    log.warn("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: no mapping for snapshotId={}", snapshot.getSnapshotId());
363→                    continue;
364→                }
365→
366→                CollabspaceVersionSnapshotEntity newSnapshot = CollabspaceVersionSnapshotEntity.builder()
367→                        .nodeId(newSpaceNodeEntity.getId())
368→                        .snapshotId(newSnapshotFileId)
369→                        .snapshotName(snapshot.getSnapshotName())
370→                        .snapshotStatus(VersionSnapshotStatusEnum.ENABLED.getValue())
371→                        .operatorId(userId)
372→                        .build();
373→                versionSnapshotService.save(newSnapshot);
374→
375→                SpaceNodeEntity snapshotSpaceNode = SpaceNodeEntity.builder()
376→                        .appSpaceNodeId(newSnapshotFileId)
377→                        .name(snapshot.getSnapshotName())
378→                        .type(newSpaceNodeEntity.getType())
379→                        .description("")
380→                        .spaceId(targetSpaceId)
381→                        .createdBy(userId)
382→                        .updatedBy(userId)
383→                        .isSnapshot(SpaceNodeSnapshotEnum.SNAPSHOT.getValue())
384→                        .build();
385→                spaceNodeService.save(snapshotSpaceNode);
386→
387→                log.info("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: copied snapshot, originalSnapshotId={}, newSnapshotId={}, newNodeId={}",
388→                        snapshot.getSnapshotId(), newSnapshotFileId, newSpaceNodeEntity.getId());
389→
390→            } catch (Exception e) {
391→                log.error("[lbl][2122-文件迁移][Migration][COPY] 版本快照迁移: failed to copy snapshot, originalNodeId={}, snapshotId={}, error={}",
392→                        originalNodeId, snapshot.getSnapshotId(), e.getMessage(), e);
393→            }
394→        }
395→    }
