397→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
398→        ObjectMapper mapper = objectMapper.copy();
399→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
400→        SimpleModule module = new SimpleModule();
401→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
402→        mapper.registerModule(module);
403→        JavaType treeNodeType =
404→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
405→        JavaType listType =
406→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
407→        return mapper.readValue(json, listType);
408→    }
